import React, { useState } from 'react';
import './Game.css';

function Square() {
    // Utilise l'état local pour gérer la taille et la couleur du carré
    const [size, setSize] = useState(100);
    const [color, setColor] = useState('#3498db');

    const handleClick = () => {
        setSize(size === 100 ? 150 : 100); // Bascule entre 100px et 150px
        setColor(color === '#3498db' ? '#e74c3c' : '#3498db'); // Change de couleur
    };

    return (
        <div
            className="square"
            onClick={handleClick}
            style={{
                width: `${size}px`,
                height: `${size}px`,
                backgroundColor: color,
            }}
        ></div>
    );
}

export default Square;
